+	customImage := "mycustom/image:v1"
+	config = GetDefaultConfig(customImage)
+	if config.Image != customImage {
+		t.Errorf("GetDefaultConfig(%v) Image = %v, want %v", customImage, config.Image, customImage)
+	}
+	if config.RemoteUser != "vscode" {
